import logging
from dataclasses import dataclass
from typing import Dict
import unittest

# Configure logging for production monitoring
logging.basicConfig(level=logging.INFO, format='%(levelname)s: %(message)s')
logger = logging.getLogger(__name__)

@dataclass
class InventoryItem:
    """Data model representing an item in the inventory."""
    sku: str
    name: str
    quantity: int

class InventoryManager:
    """Handles inventory operations with validation and low-stock alerts."""

    LOW_STOCK_THRESHOLD = 5

    def __init__(self) -> None:
        self._items: Dict[str, InventoryItem] = {}

    def add_item(self, sku: str, name: str, quantity: int) -> None:
        """Adds a new item to the inventory."""
        if quantity < 0:
            raise ValueError("Initial quantity cannot be negative.")
        if sku in self._items:
            raise ValueError(f"SKU {sku} already exists.")

        self._items[sku] = InventoryItem(sku=sku, name=name, quantity=quantity)
        logger.info(f"Added {name} ({sku}) with quantity {quantity}")
        self._check_low_stock(self._items[sku])

    def update_stock(self, sku: str, delta: int) -> None:
        """Updates stock levels and triggers alerts if below threshold."""
        if sku not in self._items:
            raise KeyError(f"SKU {sku} not found.")

        item = self._items[sku]
        if item.quantity + delta < 0:
            raise ValueError("Resulting stock cannot be negative.")

        item.quantity += delta
        logger.info(f"Updated {sku}: new quantity {item.quantity}")
        self._check_low_stock(item)

    def _check_low_stock(self, item: InventoryItem) -> None:
        """Internal logic to trigger alerts for low stock."""
        if item.quantity < self.LOW_STOCK_THRESHOLD:
            logger.warning(f"ALERT: Low stock for {item.name} ({item.sku}). Current: {item.quantity}")

class TestInventoryManager(unittest.TestCase):
    """Unit tests for InventoryManager."""

    def setUp(self) -> None:
        self.manager = InventoryManager()

    def test_add_item(self) -> None:
        self.manager.add_item("A1", "Widget", 10)
        self.assertEqual(self.manager._items["A1"].quantity, 10)

    def test_negative_initial_stock(self) -> None:
        with self.assertRaises(ValueError):
            self.manager.add_item("A2", "BadItem", -1)

    def test_update_stock(self) -> None:
        self.manager.add_item("A1", "Widget", 10)
        self.manager.update_stock("A1", -5)
        self.assertEqual(self.manager._items["A1"].quantity, 5)

    def test_low_stock_trigger(self) -> None:
        self.manager.add_item("B1", "Gadget", 6)
        with self.assertLogs(logger, level='WARNING') as cm:
            self.manager.update_stock("B1", -2)
            self.assertTrue(any("Low stock" in output for output in cm.output))

    def test_non_existent_sku(self) -> None:
        with self.assertRaises(KeyError):
            self.manager.update_stock("MISSING", 10)

if __name__ == "__main__":
    unittest.main()
